parameters.resumeTime:
={{ 
  (() => {
    const now = DateTime.now().setZone('Europe/London');
    const day = now.weekday; // 1=Mon, 7=Sun
    const hour = now.hour;

    // Fri/Sat/Sun leads → Saturday 10am
    if (day >= 5) {
      const sat = now.plus({ days: (7 - day + 6) % 7 || 7 });
      return sat.set({ hour: 10, minute: 0, second: 0 }).toISO();
    }

    // Mon-Thu: next Tue/Wed/Thu 7:30pm
    // If it's before 6pm today and Tue/Wed/Thu, publish tonight
    if (day >= 2 && day <= 4 && hour < 18) {
      return now.set({ hour: 19, minute: 30, second: 0 }).toISO();
    }

    // Otherwise push to next weekday evening
    const nextDay = day >= 4 ? now.plus({ days: 4 }) : now.plus({ days: 1 });
    return nextDay.set({ hour: 19, minute: 30, second: 0 }).toISO();
  })()
}}
